def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    term1 = ((ratio - a) ** 6) / (a * b * 1.1 + 0.5)
                    term2 = np.sin(ratio * b / (a + 0.5)) * np.cos(ratio / (b + 1))
                    priority += term1 * term2 * np.exp(-ratio / (a + b))
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.2)) ** 1.7
        elif 4 < ratio <= 7:
            for c in range(1, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 3):
                    term = ((ratio - c) ** 4) * np.tan(ratio * c / (d + 1)) / (d + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4.5) * 3
        elif 2 <= ratio <= 4:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 2) ** e) / (e * 2) * np.sin(e * ratio * 1.1)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
        elif 1 <= ratio < 2:
            s = 0
            for f in range(1, 12):
                s += ((2 - ratio) ** f) / (f ** 2 + 1) * np.cos(f * ratio * 1.3)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for g in range(1, 6):
                priority += np.sin(g * ratio * i * 0.9) * ((ratio - 1) ** g) / (g ** 0.5 + 1)
        elif 0.5 <= ratio < 1:
            s = 0
            for h in range(1, 20):
                s += ((1 - ratio) ** h) / (h * 5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for l in range(1, 9):
                priority += ((0.5 - ratio) ** l) / (l * 7) * np.cos(item * l * 1.3)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for m in range(1, 15):
                s += ((0.2 - ratio) ** m) / (m * 4) * np.sin(m * item * 1.4)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 1.1) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for n in range(1, 10):
                priority += ((0.2 - ratio) ** n) / (n * 8) * np.cos(item * n * 1.1)
        else:
            s = 0
            for o in range(1, 12):
                s += ((0.05 - ratio) ** o) / (o * 6) * np.cos(o * item * 0.7)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.08:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for p in range(1, 12):
                priority += ((0.05 - ratio) ** p) / (p * 9) * np.sin(item * p * 0.6)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for q in range(1, 5):
            if (i + q) % 4 == 0:
                priority += np.sin(ratio * (i + q) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + q) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if i % 2 == 0 and bin_cap % 2 == 0:
            for r in range(1, 4):
                priority += np.tanh((ratio * r) / (i + r + 1)) * 0.5
        else:
            for s in range(1, 4):
                priority -= np.tanh((ratio * s) / (i + s + 1)) * 0.5
        priorities[i] = priority
    return priorities
